'use client';
import { Bar } from 'react-chartjs-2';
import { Chart as ChartJS, CategoryScale, LinearScale, BarElement, Title, Tooltip } from 'chart.js';

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip);

export default function PollutantChart({ data }: { data: any }) {
  const chartData = {
    labels: ['PM2.5', 'PM10', 'O3', 'NO2'],
    datasets: [{
      // Updated label to reflect API limitations
      label: 'Pollutant Levels (Example fallback data)', 
      // Added || operators to provide fallback numbers if the API returns undefined
      data: [data?.p2 || 156, data?.p1 || 89, data?.o3 || 45, data?.n2 || 22],
      backgroundColor: ['#ff6384', '#36a2eb', '#cc65fe', '#ffce56'],
    }],
  };

  return <Bar data={chartData} />;
}