export default function AICounsel({ insight }: { insight: string }) {
  // A simple function to turn **bold** markdown into HTML tags
  const formatText = (text: string) => {
    return text.replace(/\*\*(.*?)\*\*/g, '<strong class="text-blue-900">$1</strong>');
  };

  return (
    <div className="bg-white border-l-4 border-blue-500 p-8 rounded-3xl shadow-sm hover:shadow-md transition-shadow">
      <h4 className="flex items-center gap-3 font-bold text-blue-600 text-lg mb-4">
        <span className="text-2xl">✨</span> AI Health Protocol
      </h4>
      
      {insight ? (
        <p 
          className="text-gray-700 whitespace-pre-line leading-relaxed"
          dangerouslySetInnerHTML={{ __html: formatText(insight) }} 
        />
      ) : (
        <div className="animate-pulse flex space-x-4">
          <div className="flex-1 space-y-4 py-1">
            <div className="h-4 bg-gray-200 rounded w-3/4"></div>
            <div className="h-4 bg-gray-200 rounded w-5/6"></div>
          </div>
        </div>
      )}
    </div>
  );
}